import {useMutation,useQueryClient,QueryClient,QueryClientProvider} from '@tanstack/react-query';
import {describe,it,expect,vi} from 'vitest';
import {renderHook,waitFor} from '@testing-library/react';

function useToggleLike(){
  const qc=useQueryClient();
  return useMutation({
    mutationFn:async()=>{throw new Error('fail');},
    onMutate:async()=>{
      const prev=qc.getQueryData<number>(['likes']);
      qc.setQueryData(['likes'],(prev??0)+1);
      return {prev};
    },
    onError:(_e,_v,ctx)=>{if(ctx?.prev!==undefined)qc.setQueryData(['likes'],ctx.prev);}
  });
}

describe('useToggleLike rollback',()=>{
  it('restores previous value on error',async()=>{
    const qc=new QueryClient({defaultOptions:{mutations:{retry:false}}});
    qc.setQueryData(['likes'],10);
    const {result}=renderHook(()=>useToggleLike(),{wrapper:({children})=><QueryClientProvider client={qc}>{children}</QueryClientProvider>});
    result.current.mutate();
    await waitFor(()=>expect(result.current.isError).toBe(true));
    expect(qc.getQueryData(['likes'])).toBe(10);
  });
});

