export function rollingAvgFast(arr:number[],w:number):number[]{
  const out:number[]=[];
  let sum=0;
  for(let i=0;i<arr.length;i++){
    sum+=arr[i];
    if(i>=w)sum-=arr[i-w];
    if(i>=w-1)out.push(sum/w);
  }
  return out;
}
function rollingAvgSlow(arr:number[],w:number):number[]{
  const out:number[]=[];
  for(let i=w-1;i<arr.length;i++){
    let s=0;for(let j=i-w+1;j<=i;j++)s+=arr[j];
    out.push(s/w);
  }
  return out;
}

import {describe,it} from 'vitest';
import fc from 'fast-check';

describe('rolling avg',()=>{
  it('fast matches slow',()=>{
    fc.assert(fc.property(fc.array(fc.integer({min:-100,max:100}),{minLength:1,maxLength:100}),fc.integer({min:1,max:10}),(arr,w)=>{
      const W=Math.min(w,arr.length);
      const a=rollingAvgFast(arr,W);
      const b=rollingAvgSlow(arr,W);
      if(a.length!==b.length)return false;
      return a.every((v,i)=>Math.abs(v-b[i])<1e-9);
    }),{numRuns:300});
  });
});

