export function safeStringify(o:unknown):string{
  const seen=new WeakSet();
  return JSON.stringify(o,(_k,v)=>{
    if(typeof v==='object'&&v!==null){
      if(seen.has(v))return '[Circular]';
      seen.add(v);
    }
    return v;
  });
}

