import { test, expect } from '@playwright/test';

const swV1 = `self.addEventListener('install', () => self.skipWaiting()); self.addEventListener('activate', (e) => e.waitUntil(self.clients.claim()));`;
const swV2 = `self.addEventListener('install', () => self.skipWaiting()); self.addEventListener('activate', (e) => e.waitUntil(self.clients.claim().then(() => self.clients.matchAll()).then(cs => cs.forEach(c => c.postMessage({ type: 'UPDATE_READY' })))));`;

test('update prompt appears when a new service worker activates', async ({ page }) => {
  let version = 1;
  await page.route('/sw.js', (route) => route.fulfill({ contentType: 'text/javascript', body: version === 1 ? swV1 : swV2, headers: { 'Cache-Control': 'no-store' } }));
  await page.goto('/');
  await page.evaluate(() => navigator.serviceWorker.register('/sw.js'));
  await expect.poll(() => page.evaluate(() => !!navigator.serviceWorker.controller)).toBeTruthy();

  version = 2;
  await page.evaluate(async () => { const reg = await navigator.serviceWorker.getRegistration('/'); await reg?.update(); });
  await expect(page.getByRole('alert', { name: /update available/i })).toBeVisible();
});
